const upperLen = 90;
const foreLen = 75;

const mech = assembly("Notebook Debug Arm")
  .addPart("Base", box(44, 44, 18, true).color("#6e7f96"))
  .addPart(
    "Upper Arm",
    box(upperLen, 18, 18).translate(0, -9, -9).color("#d0a24c"),
  )
  .addPart(
    "Forearm",
    box(foreLen, 14, 14).translate(0, -7, -7).color("#b86656"),
  )
  .addJoint("shoulder", "revolute", "Base", "Upper Arm", {
    axis: [0, 1, 0],
    min: -45,
    max: 110,
    default: 25,
    frame: Transform.identity().translate(0, 0, 18),
  })
  .addJoint("elbow", "revolute", "Upper Arm", "Forearm", {
    axis: [0, -1, 0],
    min: -10,
    max: 135,
    default: 35,
    frame: Transform.identity().translate(upperLen, 0, 0),
  });

const solved = mech.solve({ shoulder: 38, elbow: 72 });
const collisions = solved.collisionReport({
  minOverlapVolume: 0.5,
  ignorePairs: [["Upper Arm", "Forearm"]],
});

console.log("Collision report", collisions);
show(solved);

const sweepFrames = mech.sweepJoint("elbow", -10, 135, 14, { shoulder: 38 });
const collidingSteps = sweepFrames.filter((step) => step.collisions.length > 0).length;

console.log("Sweep collisions", collidingSteps, "of", sweepFrames.length);
show(mech.solve({ shoulder: 38, elbow: 90 }));
